import { useState } from "react";
import { AsyncPaginate } from "react-select-async-paginate";
import { GEO_API_URL, geoApiOptions } from "../../api";

const Search = ({onSearchChange}) => {

    const [search, setSearch] = useState(null);

    const loadOptions = async (inputValue, prevOptions, { page }) => {
        // We're making a request to an API (a place where we get information from).
        try {
          const response = await fetch(
            `${GEO_API_URL}?namePrefix=${inputValue}&offset=${page * 10}`,
            geoApiOptions
          );

          // The API sends us some information back, and we're converting it to a readable format.
          const result = await response.json();

          // We're creating a list of options (like choices) from the information we got.
          const options = result.data.map(city => ({
            label: city.name,
            value: city.name
          }));

          return {
            options,
            hasMore: page < result.metadata.totalPages
          };
        } catch (error) {
          console.error(error);
          return {
            options: [],
            hasMore: false
          };
        }
      };

    const handleOnChange = (searchData) => {
        setSearch(searchData);
        onSearchChange(searchData);
    }

    return (<AsyncPaginate 
        placeholder = "Search for city"
        debounceTimeout={600}
        value={search}
        onChange = {handleOnChange}
        loadOptions = {loadOptions}
        />);
}

export default Search;
